import React, { useState } from "react";
import "./Men.css"; // reuse same styling

const kidsProducts = [
  { id: 1, name: "Kids Casual Wear", price: 25, image: "/images/kids/kids1.jpg" },
  { id: 2, name: "Kids Party Dress", price: 35, image: "/images/kids/kids2.jpg" },
  { id: 3, name: "Kids T-Shirt", price: 18, image: "/images/kids/kids3.jpg" },
  { id: 4, name: "Kids Jeans", price: 30, image: "/images/kids/kids4.jpg" },
  { id: 5, name: "Kids Jacket", price: 45, image: "/images/kids/kids5.jpg" },
  { id: 6, name: "Kids Hoodie", price: 40, image: "/images/kids/kids6.jpg" },
  { id: 7, name: "Kids Shorts", price: 20, image: "/images/kids/kids7.jpg" },
  { id: 8, name: "Kids Ethnic Wear", price: 50, image: "/images/kids/kids8.jpg" },
];

const Kids = () => {
  const [qty, setQty] = useState({});

  const increase = (id) =>
    setQty((prev) => ({ ...prev, [id]: (prev[id] || 0) + 1 }));

  const decrease = (id) =>
    setQty((prev) => ({ ...prev, [id]: Math.max((prev[id] || 0) - 1, 0) }));

  return (
    <div className="men-page">
      <h2 className="men-title">Kids Collection</h2>

      <div className="men-grid">
        {kidsProducts.map((item) => (
          <div className="men-card" key={item.id}>
            {/* IMAGE FIX (SAME SIZE FOR ALL) */}
            <div className="men-img-box">
              <img src={item.image} alt={item.name} />
            </div>

            <div className="men-info">
              <h3>{item.name}</h3>
              <p className="price">${item.price}</p>

              <div className="qty-box">
                <button onClick={() => decrease(item.id)}>-</button>
                <span>{qty[item.id] || 0}</span>
                <button onClick={() => increase(item.id)}>+</button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Kids;
